from itertools import product

def solve():
    n = int(input())
    a = list(map(int, input().split()))

    # Check if any non-all-zero assignment of coefficients in {-1, 0, 1}
    # to elements of a gives sum = 0
    for coeffs in product([-1, 0, 1], repeat=n):
        if all(c == 0 for c in coeffs):
            continue
        s = sum(c * a[i] for i, c in enumerate(coeffs))
        if s == 0:
            print("YES")
            return

    print("NO")

t = int(input())
for _ in range(t):
    solve()
